<template>
  <Switch
      :class="{ '-hidden': !this.show_switch }"
      :switchName="payment_methods[index].name"
      :switchChecked="payment_methods[index].checked ? true : null"
      :switchData="'paymentMethod_' + payment_methods[index].name"
      :style="[payment_methods[index].hide === true ? {'z-index':'-1'} : '' ]"
  />
  <Image :imageSrc="payment_methods[index].image" imgParentClass="_logo"/>
  <PMethodHeader :description="description" :title="payment_methods[index].title" :links="links" :primary="true"/>
  <PMethodInformations
      v-show="show_options"
      :paymentMethod="payment_methods[index]"/>
</template>

<script>
import Switch from "@/components/atoms/AtomSwitch";
import Image from "@/components/atoms/AtomURLImage";
import PMethodHeader from "@/components/organisms/PMethod/OrganismPMethodHeader";
import PMethodInformations from "@/components/organisms/PMethod/OrganismPMethodInformations";
import {store} from "@/store/store";

export default {
  name: "OrganismPMethodFull",
  components: {Switch, Image, PMethodHeader, PMethodInformations},
  computed: {
    payment_methods: {
      get: () => store.translations.payment_methods.payment_methods
    },
    show_options: {
      get() {
        return this.store.data['enable_' + this.payment_methods[this.index].name];
      }
    }
  },
  props: {
    index: {
      type: Number,
      required: true
    }
  },
  created() {
    this.init();
  },
  updated() {
    this.init();
  },
  data() {
    return {
      store: store,
      show_switch: false
    };
  },
  methods: {
    init() {
      this.description = this.payment_methods[this.index].description;
      this.links = this.payment_methods[this.index].link_know_more ?? null;
      this.show_switch = this.showSWitch();
    },
    showSWitch() {
      var avai = this.payment_methods[this.index].test_mode_avail
      var hide = this.payment_methods[this.index].hide
      var mode = store.settings.mode === 0; // true = is live

      if (hide === true)
        return false

      if ((avai && !mode) || mode)
        return true;

      return false;
    }
  }
}
</script>

